const item = $input.first().json;
const raw =
  typeof item.text === 'string'
    ? item.text
    : typeof item.output === 'string'
      ? item.output
      : '';

// Strip markdown code fences if the LLM wrapped its JSON in them
let stripped = String(raw)
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let data = null;
try {
  data = JSON.parse(stripped);
} catch (e) {
  // Last-ditch: find the first {...} block
  const m = stripped.match(/\{[\s\S]*\}/);
  if (m) {
    try { data = JSON.parse(m[0]); } catch (e2) {}
  }
}

function asArray(v) {
  if (Array.isArray(v)) return v.slice(0, 5).map(String);
  if (typeof v === 'string' && v.trim()) {
    return v.split(/[,\n]/).map(s => s.trim()).filter(Boolean).slice(0, 5);
  }
  return [];
}

function asNumberOrNull(v) {
  if (typeof v === 'number' && isFinite(v)) return v;
  if (v == null || v === '') return null;
  const n = Number(String(v).replace(/[,_\s]/g, ''));
  return isFinite(n) ? n : null;
}

const fallback = {
  property_type: 'other',
  location: '',
  price_ils: null,
  num_rooms: null,
  size_sqm: null,
  key_features: [],
  certifications: '',
};

if (!data || typeof data !== 'object') {
  return [{ json: { output: fallback, extract_error: true, raw_preview: String(raw).slice(0, 500) } }];
}

const allowed = ['apartment','house','villa','office','retail','industrial','other'];
const pt = String(data.property_type || 'other').toLowerCase();

const output = {
  property_type: allowed.includes(pt) ? pt : 'other',
  location: data.location ? String(data.location) : '',
  price_ils: asNumberOrNull(data.price_ils),
  num_rooms: asNumberOrNull(data.num_rooms),
  size_sqm: asNumberOrNull(data.size_sqm),
  key_features: asArray(data.key_features),
  certifications: data.certifications != null ? String(data.certifications) : '',
};

return [{ json: { output } }];

