const item = $input.first().json;
const raw =
  typeof item.text === 'string'
    ? item.text
    : typeof item.output === 'string'
      ? item.output
      : '';

let stripped = String(raw)
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let data = null;
try {
  data = JSON.parse(stripped);
} catch (e) {
  const m = stripped.match(/\{[\s\S]*\}/);
  if (m) {
    try { data = JSON.parse(m[0]); } catch (e2) {}
  }
}

// Some LLMs wrap the report inside { report: {...} } — unwrap it
if (data && data.report && typeof data.report === 'object' && !Array.isArray(data.report)) {
  data = data.report;
}

const fallback = {
  property_type: 'unknown',
  routing_decision: 'residential',
  location: 'unknown',
  price_ils: null,
  num_rooms: null,
  size_sqm: null,
  key_features: [],
  image_scores: [],
  similar_listings: [],
  rag_insight: '',
  enrichment_notes: 'Could not parse final report JSON from the LLM chain output.',
  confidence: 0,
  markdown_summary: '',
  parse_error: true,
};

if (!data || typeof data !== 'object') {
  return [{ json: { ...fallback, raw_preview: typeof raw === 'string' ? raw.slice(0, 800) : '' } }];
}

// Normalise routing_decision
const rd = String(data.routing_decision || '').toLowerCase().trim();
data.routing_decision = (rd === 'residential' || rd === 'commercial') ? rd : 'residential';

return [{ json: data }];

const item = $input.first().json;

let output = item.output;

// If AI Agent output is a JSON string, parse it
if (typeof output === 'string') {
  let cleaned = output
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();

  try {
    output = JSON.parse(cleaned);
  } catch (e) {
    return [{
      json: {
        output: item.output,
        normalize_error: true,
        error: 'Could not parse AI Agent output as JSON'
      }
    }];
  }
}

// Normalize image_scores
if (output && Array.isArray(output.image_scores)) {
  output.image_scores = output.image_scores.map(score => ({
    url: score.url || score.image_url || '',
    room_type: score.room_type || '',
    condition_score: score.condition_score ?? null,
    confidence: score.confidence ?? null
  }));
}

return [{
  json: {
    output
  }
}];
